INSERT INTO tracks (name, description, is_active, created_at) VALUES
                                                                  ('Junior Android Developer', 'Entry-level native Android track covering Kotlin, Android fundamentals, Jetpack Compose, persistence, networking, and testing.', TRUE, NOW()),
                                                                  ('Mid-Level Android Developer', 'Production-focused Android track covering advanced Kotlin coroutines, Compose state, modular architecture, offline-first data, reliability, and performance.', TRUE, NOW()),
                                                                  ('Senior Android Engineer', 'Senior Android engineering track covering architecture at scale, build systems, performance, resilience, security, release engineering, and technical leadership.', TRUE, NOW()),
                                                                  ('iOS Developer', 'Native iOS development track covering Swift, SwiftUI, UIKit, concurrency, persistence, architecture, testing, and performance.', TRUE, NOW()),
                                                                  ('Frontend Engineer', 'Modern frontend engineering track covering JavaScript, TypeScript, React, browser behavior, accessibility, testing, security, and performance.', TRUE, NOW()),
                                                                  ('Backend Engineer', 'Backend engineering track covering APIs, data stores, distributed systems, reliability, security, testing, and scalable system design.', TRUE, NOW()),
                                                                  ('Full-Stack Engineer', 'End-to-end web engineering track covering frontend, backend, databases, contracts, deployment, testing, observability, and product reliability.', TRUE, NOW()),
                                                                  ('DevOps and Site Reliability Engineer', 'Platform and reliability track covering Linux, networking, containers, Kubernetes, infrastructure as code, SLOs, incident response, security, and cost.', TRUE, NOW()),
                                                                  ('Data Analyst', 'Analytics track covering SQL, statistics, experimentation, dashboards, data quality, Python, business metrics, and stakeholder communication.', TRUE, NOW()),
                                                                  ('Data Engineer', 'Data engineering track covering modeling, batch and streaming pipelines, orchestration, lakehouse systems, data quality, governance, observability, and cost.', TRUE, NOW()),
                                                                  ('Machine Learning Engineer', 'Applied machine-learning track covering problem formulation, data, model development, evaluation, deployment, monitoring, responsible AI, and ML system design.', TRUE, NOW()),
                                                                  ('QA Automation Engineer', 'Quality engineering track covering test strategy, API and UI automation, reliability, CI execution, mobile testing, performance, accessibility, and automation architecture.', TRUE, NOW()),
                                                                  ('Cybersecurity Engineer', 'Application and infrastructure security track covering risk, threat modeling, identity, web and cloud security, cryptography, monitoring, incident response, and secure delivery.', TRUE, NOW());
